public static long solve(long sx, long sy, long tx, long ty) {
    // If the starting point is the target, return 0
    if (sx == tx && sy == ty) {
        return 0;
    }

    // If the target is not reachable, return -1
    if (tx < sx || ty < sy) {
        return -1;
    }

    long steps = 0;
    while (sx < tx || sy < ty) {
        long m = Math.max(sx, sy);
        if (sx < tx) {
